import { useRender } from "@base-ui/react";
import type { StyleXStyles } from "@stylexjs/stylex";
import * as stylex from "@stylexjs/stylex";

import { Separator } from "../separator/separator";
import { styles } from "./item.stylex";

type ItemVariant = "default" | "outline" | "muted";
type ItemSize = "default" | "sm" | "xs";

const variantStyles: Record<ItemVariant, StyleXStyles> = {
  default: null,
  muted: styles.variantMuted,
  outline: styles.variantOutline,
};

const sizeStyles: Record<ItemSize, StyleXStyles> = {
  default: styles.sizeDefault,
  sm: styles.sizeSm,
  xs: styles.sizeXs,
};

const mediaVariantStyles: Record<"default" | "icon" | "image", StyleXStyles> = {
  default: styles.mediaDefault,
  icon: styles.mediaIcon,
  image: styles.mediaImage,
};

const ItemGroup = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = stylex.props(styles.group);
  return (
    <div
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-group"
      role="list"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ItemSeparator = ({
  className,
  ...props
}: React.ComponentProps<typeof Separator>) => {
  const p = stylex.props(styles.separator);
  return (
    <Separator
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-separator"
      orientation="horizontal"
      {...props}
    />
  );
};

const Item = ({
  className,
  style,
  variant = "default",
  size = "default",
  render,
  ...props
}: React.ComponentProps<"div"> & {
  variant?: ItemVariant;
  size?: ItemSize;
  render?: useRender.RenderProp;
}) => {
  const p = stylex.props(styles.base, variantStyles[variant], sizeStyles[size]);
  return useRender({
    props: {
      className:
        [p.className, className].filter(Boolean).join(" ") || undefined,
      "data-size": size,
      "data-slot": "item",
      "data-variant": variant,
      style: { ...p.style, ...style },
      ...props,
    },
    render: render ?? <div />,
  });
};

const ItemMedia = ({
  className,
  style,
  variant = "default",
  ...props
}: React.ComponentProps<"div"> & {
  variant?: "default" | "icon" | "image";
}) => {
  const p = stylex.props(styles.mediaBase, mediaVariantStyles[variant]);
  return (
    <div
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-media"
      data-variant={variant}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ItemContent = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = stylex.props(styles.content);
  return (
    <div
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-content"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ItemTitle = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = stylex.props(styles.title);
  return (
    <div
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-title"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ItemDescription = ({
  className,
  style,
  ...props
}: React.ComponentProps<"p">) => {
  const p = stylex.props(styles.description);
  return (
    <p
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-description"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ItemActions = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = stylex.props(styles.actions);
  return (
    <div
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-actions"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ItemHeader = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = stylex.props(styles.header);
  return (
    <div
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-header"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ItemFooter = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = stylex.props(styles.footer);
  return (
    <div
      className={
        [p.className, className].filter(Boolean).join(" ") || undefined
      }
      data-slot="item-footer"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

export {
  Item,
  ItemMedia,
  ItemContent,
  ItemActions,
  ItemGroup,
  ItemSeparator,
  ItemTitle,
  ItemDescription,
  ItemHeader,
  ItemFooter,
};

import * as stylex from "@stylexjs/stylex";

import { colors, radius } from "../tokens.stylex";

export const styles = stylex.create({
  actions: {
    alignItems: "center",
    display: "flex",
    gap: "0.5rem",
  },
  base: {
    alignItems: "center",
    border: "1px solid transparent",
    borderColor: {
      ":focus-visible": colors.ring,
      default: "transparent",
    },
    borderRadius: radius.md,
    boxShadow: {
      ":focus-visible": `0 0 0 3px color-mix(in oklab, ${colors.ring} 50%, transparent)`,
      default: null,
    },
    display: "flex",
    flexWrap: "wrap",
    fontSize: "0.875rem",
    outline: "none",
    transitionDuration: "100ms",
    transitionProperty: "color, background-color, border-color",
  },
  content: {
    display: "flex",
    flex: 1,
    flexDirection: "column",
    gap: "0.25rem",
  },
  description: {
    color: colors.mutedForeground,
    fontSize: "0.875rem",
    fontWeight: 400,
    lineHeight: 1.5,
    textWrap: "balance",
  },
  footer: {
    alignItems: "center",
    display: "flex",
    flexBasis: "100%",
    gap: "0.5rem",
    justifyContent: "space-between",
  },
  group: {
    display: "flex",
    flexDirection: "column",
  },
  header: {
    alignItems: "center",
    display: "flex",
    flexBasis: "100%",
    gap: "0.5rem",
    justifyContent: "space-between",
  },
  mediaBase: {
    alignItems: "center",
    display: "flex",
    flexShrink: 0,
    gap: "0.5rem",
    justifyContent: "center",
  },
  mediaDefault: {
    backgroundColor: "transparent",
  },
  mediaIcon: {
    backgroundColor: colors.muted,
    border: `1px solid ${colors.border}`,
    borderRadius: radius.sm,
    height: "2rem",
    width: "2rem",
  },
  mediaImage: {
    borderRadius: radius.sm,
    height: "2.5rem",
    overflow: "hidden",
    width: "2.5rem",
  },
  separator: {
    marginBlock: 0,
  },
  sizeDefault: {
    gap: "1rem",
    padding: "1rem",
  },
  sizeSm: {
    gap: "0.625rem",
    paddingBlock: "0.75rem",
    paddingInline: "1rem",
  },
  sizeXs: {
    gap: "0.5rem",
    paddingBlock: "0.5rem",
    paddingInline: "0.75rem",
  },
  title: {
    alignItems: "center",
    display: "flex",
    fontSize: "0.875rem",
    fontWeight: 500,
    gap: "0.5rem",
    lineHeight: 1.375,
    width: "fit-content",
  },
  variantMuted: {
    backgroundColor: `color-mix(in oklab, ${colors.muted} 50%, transparent)`,
  },
  variantOutline: {
    borderColor: colors.border,
  },
});
